function loadLanguageSwitcher(){document.querySelectorAll('[data-include="includes/language-switcher.html"]').forEach(t=>{if("true"!==t.getAttribute("data-loaded")){t.setAttribute("data-include-special","true"),t.setAttribute("data-loading","true");let e="";window.location.pathname.includes("/features/")?e="../../":/^\/(fr|es|ar)\//.test(window.location.pathname)&&(e="../");var a,n=e+"includes/language-switcher.html";/^\/(fr|es|ar)\//.test(window.location.pathname)&&(a=document.querySelector('[data-include="includes/language-switcher.html"]'))&&a.setAttribute("data-include-ignore","true"),fetch(n).then(e=>{if(e.ok)return e.text();throw new Error("Failed to load language switcher: "+e.status)}).then(e=>{t.innerHTML=e,t.setAttribute("data-loaded","true"),t.removeAttribute("data-loading"),window.initLanguageSwitcher&&window.initLanguageSwitcher()}).catch(e=>{console.error("Error loading language switcher:",e),t.innerHTML='<div class="language-switcher-error">Error loading language switcher</div>',t.removeAttribute("data-loading")})}})}document.addEventListener("DOMContentLoaded",function(){loadLanguageSwitcher()});